#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m;
long long a[N],t[4*N],tag[4*N];

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void modify(int cur,int l,int r,int x,int y,long long k){
    if(x<=l && r<=y){
        t[cur]+=1LL*(r-l+1)*k,tag[cur]+=k;
        return;
    }
    int mid=l+r>>1;
    if(tag[cur]){
        tag[cur*2]+=tag[cur],tag[cur*2+1]+=tag[cur];
        t[cur*2]+=tag[cur]*(mid-l+1),t[cur*2+1]+=tag[cur]*(r-mid);
        tag[cur]=0;
    }
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=t[cur*2]+t[cur*2+1];
}

long long query(int cur,int l,int r,int x){
    if(r<=x)
        return t[cur];
    int mid=l+r>>1;
    if(tag[cur]){
        tag[cur*2]+=tag[cur],tag[cur*2+1]+=tag[cur];
        t[cur*2]+=tag[cur]*(mid-l+1),t[cur*2+1]+=tag[cur]*(r-mid);
        tag[cur]=0;
    }
    long long ans=0;
    ans+=query(cur*2,l,mid,x);
    if(x>mid)
        ans+=query(cur*2+1,mid+1,r,x);
    return ans;
}

int main(){
    scanf("%d%d",&n,&m);
    long long last=0,x;
    for(int i=1;i<=n;i++){
        scanf("%lld",&x);
        a[i]=x-last,last=x;
    }
    build(1,1,n);
    while(m--){
        int tp;
        scanf("%d",&tp);
        if(tp==1){
            int l,r,k,d;
            scanf("%d%d%d%d",&l,&r,&k,&d);
            modify(1,1,n,l,l,k);
            if(l<r)
                modify(1,1,n,l+1,r,d);
            if(r<n)
                modify(1,1,n,r+1,r+1,-(k+1LL*(r-l)*d));
        }else{
            int p;
            scanf("%d",&p);
            printf("%lld\n",query(1,1,n,p));
        }
    }
    return 0;
}
